async (params, browser) => {
  // Open Bandcamp tag page
  await browser.open(`https://bandcamp.com/tag/${params.tag}`)

  // Wait for tag page
  await browser.waitForSelector('#pagedata, .hub-columns', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Extract tag results
  const result = await browser.evaluate(`const items = []; try { const pageData = document.querySelector('#pagedata'); if (pageData) { const blob = JSON.parse(pageData.getAttribute('data-blob') || '{}'); const tabs = blob?.hub?.tabs || []; for (const tab of tabs) { const collections = tab?.collections || []; for (const col of collections) { const colItems = col?.items || []; for (const item of colItems) { if (items.length < 20) { items.push({ title: item.title || '', artist: item.artist || item.band_name || '', url: item.tralbum_url || item.item_url || '', art_id: item.art_id || '', genre: item.genre || '' }); } } } } } } catch(e) {} if (items.length === 0) { document.querySelectorAll('.music-grid .music-grid-item, .item_list .item, li[data-item-id]').forEach((el, i) => { if (i < 20) { const linkEl = el.querySelector('a[href]'); const titleEl = el.querySelector('.title, .tralbum-name'); const artistEl = el.querySelector('.artist-override, .tralbum-artist'); items.push({ title: titleEl?.textContent?.trim() || linkEl?.textContent?.trim() || '', artist: artistEl?.textContent?.trim() || '', url: linkEl?.href || '' }); } }); } return { tag: '' + params.tag + '', item_count: items.length, items };`)

  return result
}
